    'ancient_map_qishi_sheng_hai_title' => 'ഏഴ് തീരപ്രവിശ്യകളുടെ സമ്പൂർണ്ണ സമുദ്രഭൂപടം',
    'ancient_map_qishi_sheng_hai_year' => '1862–1908',
